/* ── CAROUSEL ── */
let carouselIndex = 0;
let carouselTimer = null;
const CLASSES = ['far-prev', 'prev', 'active', 'next', 'far-next'];

function initCarousel() {
  const inner = document.getElementById('carouselInner');
  if (!inner) return;
  inner.innerHTML = '';
  PHOTOS.forEach((src, i) => {
    const slide = document.createElement('div');
    slide.className = 'carousel-slide hidden';
    slide.innerHTML = `<img src="${src}" alt="Photo ${i+1}" loading="lazy" />`;
    slide.addEventListener('click', () => goToSlide(i));
    inner.appendChild(slide);
  });
  updateCarousel();
  startCarouselTimer();
}

function updateCarousel() {
  const slides = document.querySelectorAll('.carousel-slide');
  const dots = document.querySelectorAll('.cdot');
  const n = PHOTOS.length;

  slides.forEach((s, i) => {
    s.className = 'carousel-slide';
    const offset = ((i - carouselIndex) % n + n) % n;
    const mirrorOffset = n - offset;
    const minOffset = Math.min(offset, mirrorOffset);
    const isRight = offset <= n / 2;

    if (offset === 0)       s.classList.add('active');
    else if (minOffset === 1) s.classList.add(isRight ? 'next' : 'prev');
    else if (minOffset === 2) s.classList.add(isRight ? 'far-next' : 'far-prev');
    else                    s.classList.add('hidden');
  });

  dots.forEach((d, i) => d.classList.toggle('active', i === carouselIndex));
}

function goToSlide(idx) {
  carouselIndex = ((idx % PHOTOS.length) + PHOTOS.length) % PHOTOS.length;
  updateCarousel();
  resetCarouselTimer();
}

function startCarouselTimer() {
  carouselTimer = setInterval(() => {
    carouselIndex = (carouselIndex + 1) % PHOTOS.length;
    updateCarousel();
  }, 3000);
}

function resetCarouselTimer() {
  clearInterval(carouselTimer);
  startCarouselTimer();
}

/* Render dots */
function renderDots() {
  const wrap = document.getElementById('carouselDots');
  if (!wrap) return;
  wrap.innerHTML = PHOTOS.map((_, i) =>
    `<div class="cdot${i === 0 ? ' active' : ''}" onclick="goToSlide(${i})"></div>`
  ).join('');
}

/* ── TICKER ── */
function initTicker() {
  const items = ['Python','TensorFlow','ResNet50','FastAPI','React','IoT Security','IEEE Research','LLaMA 3.1','Scikit-learn','Next.js','LaTeX','MQTT','CoAP','Groq','SQL','Java','C'];
  const t = document.getElementById('ticker');
  if (!t) return;
  t.innerHTML = [...items, ...items].map(i => `<span class="ticker-item">${i}</span>`).join('');
}

/* ── SKILLS ── */
function renderSkills(cat) {
  const filtered = cat === 'all' ? SKILLS : SKILLS.filter(s => s.cat === cat);
  document.getElementById('skills-grid').innerHTML =
    filtered.map(s => `<div class="skill-pill"><span class="skill-dot ${s.dot}"></span>${s.name}</div>`).join('');
}
function filterSkills(cat, btn) {
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  renderSkills(cat);
}

/* ── PROJECTS ── */
function renderProjects() {
  document.getElementById('projects-grid').innerHTML = PROJECTS.map(p => `
    <div class="project-card">
      <div class="project-num">${p.num}</div>
      <div class="project-title">${p.title}</div>
      <div class="project-desc">${p.desc}</div>
      <div class="project-tags">${p.tags.map(t => `<span class="ptag">${t}</span>`).join('')}</div>
      <div class="project-links">${p.github ? `<a href="${p.github}" target="_blank">GitHub →</a>` : ''}</div>
    </div>`).join('');
}

/* ── RESUME DOWNLOAD ── */
function downloadCV() {
  const a = document.createElement('a');
  a.href = CV_DATA;
  a.download = 'Jai_Chadha_CV_May_2026.pdf';
  a.click();
}

/* ── SCROLL REVEAL ── */
function initReveal() {
  const obs = new IntersectionObserver(
    entries => entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); }),
    { threshold: 0.08 }
  );
  document.querySelectorAll('.reveal').forEach(el => obs.observe(el));
}

/* ── INIT ── */
document.addEventListener('DOMContentLoaded', () => {
  initTicker();
  renderDots();
  initCarousel();
  renderSkills('all');
  renderProjects();
  initReveal();
});
